#define MAX_ARGS 10
#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000.0

struct neighbor {
    char entry[REC_LENGTH];
    double dist;
};

__kernel void compute_distances(
    const char* sandbox,
    float* z,
    int rec_count,
    float target_lat,
    float target_long)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    const char* rec_iter = sandbox + (i * REC_LENGTH + LATITUDE_POS - 1);

    float tmp_lat = 0.0f;
    float tmp_long = 0.0f;

    // Parse latitude
    int idx = 0;
    while (rec_iter[idx] == ' ' && idx < 10) idx++;

    float val = 0.0f;
    float frac = 0.0f;
    float divisor = 1.0f;
    int sign = 1;

    if (rec_iter[idx] == '-') {
        sign = -1;
        idx++;
    }

    while (rec_iter[idx] >= '0' && rec_iter[idx] <= '9') {
        val = val * 10.0f + (rec_iter[idx] - '0');
        idx++;
    }

    if (rec_iter[idx] == '.') {
        idx++;
        divisor = 10.0f;
        while (rec_iter[idx] >= '0' && rec_iter[idx] <= '9') {
            frac += (rec_iter[idx] - '0') / divisor;
            divisor *= 10.0f;
            idx++;
        }
    }

    tmp_lat = sign * (val + frac);

    // Parse longitude (5 chars offset)
    const char* long_iter = rec_iter + 5;
    idx = 0;
    while (long_iter[idx] == ' ' && idx < 10) idx++;

    val = 0.0f;
    frac = 0.0f;
    divisor = 1.0f;
    sign = 1;

    if (long_iter[idx] == '-') {
        sign = -1;
        idx++;
    }

    while (long_iter[idx] >= '0' && long_iter[idx] <= '9') {
        val = val * 10.0f + (long_iter[idx] - '0');
        idx++;
    }

    if (long_iter[idx] == '.') {
        idx++;
        divisor = 10.0f;
        while (long_iter[idx] >= '0' && long_iter[idx] <= '9') {
            frac += (long_iter[idx] - '0') / divisor;
            divisor *= 10.0f;
            idx++;
        }
    }

    tmp_long = sign * (val + frac);

    double diff_lat = (double)tmp_lat - (double)target_lat;
    double diff_long = (double)tmp_long - (double)target_long;
    z[i] = (float)sqrt(diff_lat * diff_lat + diff_long * diff_long);
}

__kernel void update_neighbors(
    const char* sandbox,
    const float* z,
    struct neighbor* neighbors,
    int rec_count,
    int k)
{
    // Only thread 0 executes the sequential update loop to match original behavior
    if (get_global_id(0) != 0) return;

    for (int i = 0; i < rec_count; i++) {
        double current_dist = (double)z[i];

        // Find max distance in neighbors (sequential scan)
        double max_dist = -1.0;
        int max_idx = 0;

        for (int j = 0; j < k; j++) {
            if (neighbors[j].dist > max_dist) {
                max_dist = neighbors[j].dist;
                max_idx = j;
            }
        }

        if (current_dist < neighbors[max_idx].dist) {
            // Copy entry
            for (int c = 0; c < REC_LENGTH - 1; c++) {
                neighbors[max_idx].entry[c] = sandbox[i * REC_LENGTH + c];
            }
            neighbors[max_idx].entry[REC_LENGTH - 1] = '\0';
            neighbors[max_idx].dist = current_dist;
        }
    }
}
